import{_ as e,o as t,c as s,a5 as r}from"./chunks/framework.B5tqjWbr.js";const q=JSON.parse('{"title":"概念：三相功率与 dq 坐标变换","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：三相功率与 dq 坐标变换","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0037-three-phase-power-dq-transform.html` 的源稿。它只讨论公开三相理论和教学参数，不包含公司内部采样标定、真实项目额定功率或控制器参数。"},"headers":[],"relativePath":"content/power/concepts/power-electronics/three-phase-power-dq-transform.md","filePath":"content/power/concepts/power-electronics/three-phase-power-dq-transform.md","lastUpdated":null}'),n={name:"content/power/concepts/power-electronics/three-phase-power-dq-transform.md"};function o(l,a,i,p,h,c){return t(),s("div",null,[...a[0]||(a[0]=[r(`<h1 id="概念-三相功率与-dq-坐标变换" tabindex="-1">概念：三相功率与 dq 坐标变换 <a class="header-anchor" href="#概念-三相功率与-dq-坐标变换" aria-label="Permalink to &quot;概念：三相功率与 dq 坐标变换&quot;">​</a></h1><p>本页是 <code>lessons/0037-three-phase-power-dq-transform.html</code> 的源稿。它只讨论公开三相理论和教学参数，不包含公司内部采样标定、真实项目额定功率或控制器参数。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>三相系统（three-phase system）包含 A/B/C 三个相差 120 度的交流量。Clarke 变换（Clarke transform）把三相量变成 alpha/beta 两轴；Park 变换（Park transform）再把 alpha/beta 转到旋转 dq 坐标。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>三相 UPS、Vienna PFC、三电平逆变器和 PCS 都要用 dq 坐标表达电流、功率和电压控制目标。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>alpha = xa</span></span>
<span class="line"><span>beta  = (xa + 2 * xb) / sqrt(3)</span></span>
<span class="line"><span>d =  alpha * cos(theta) + beta * sin(theta)</span></span>
<span class="line"><span>q = -alpha * sin(theta) + beta * cos(theta)</span></span></code></pre></div><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>生成三相正弦量，比较 abc、alpha/beta 和 d/q。把 theta 偏置 10 度，观察 q 轴偏置。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能手写 Clarke/Park 公式。</li><li>能解释 dq 是坐标变化，不是新硬件量。</li><li>能说明 d/q 和 P/Q 的关系依赖 theta 对齐方式。</li></ul><h2 id="复盘问题" tabindex="-1">复盘问题 <a class="header-anchor" href="#复盘问题" aria-label="Permalink to &quot;复盘问题&quot;">​</a></h2><ul><li>为什么对称三相可以由两个独立变量表示？</li><li>theta 错误会怎样污染 q 轴？</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>阅读三相代码时，theta 来源通常从哪个模块确认？只讨论通用阅读路径，不记录公司内部实现。</p>`,16)])])}const u=e(n,[["render",o]]);export{q as __pageData,u as default};
